244→export const updateStoryService = async (storyId, userId, updates, coverFile) => {
245→    if (!storyId || !userId) {
246→        throw { status: 400, error: 'storyId and userId are required' };
247→    }
248→
249→    // Verify ownership (also grab title + description for embedding check)
250→    const { data: existing, error: fetchError } = await supabase
251→        .from('stories')
252→        .select('author_id, title, description')
253→        .eq('id', storyId)
254→        .single();
255→
256→    if (fetchError || !existing) {
257→        throw { status: 404, error: 'story not found' };
258→    }
259→    if (existing.author_id !== userId) {
260→        throw { status: 403, error: 'not authorized to update this story' };
261→    }
262→
263→    const updateData = {};
264→    if (updates.title !== undefined) {
265→        if (!updates.title || updates.title.trim().length === 0) {
266→            throw { status: 400, error: 'title cannot be empty' };
267→        }
268→        updateData.title = updates.title.trim();
269→    }
270→    if (updates.description !== undefined) {
271→        updateData.description = (updates.description || '').trim();
272→    }
273→    if (updates.status !== undefined && ['ongoing', 'completed', 'hiatus'].includes(updates.status)) {
274→        updateData.status = updates.status;
275→    }
276→    if (updates.privacy !== undefined && ['public', 'private'].includes(updates.privacy)) {
277→        updateData.privacy = updates.privacy;
278→    }
279→    if (updates.tags !== undefined) {
280→        let parsedTags = [];
281→        try {
282→            parsedTags = typeof updates.tags === 'string' ? JSON.parse(updates.tags) : updates.tags;
283→            if (!Array.isArray(parsedTags)) parsedTags = [];
284→            parsedTags = parsedTags.slice(0, 10).map(t => String(t).trim()).filter(Boolean);
285→        } catch {
286→            parsedTags = [];
287→        }
288→        updateData.tags = parsedTags;
289→    }
290→
291→    if (coverFile) {
292→        updateData.cover_url = await imageUploader(coverFile, userId, 'story-covers');
293→    }
294→
295→    if (Object.keys(updateData).length === 0) {
296→        throw { status: 400, error: 'no valid fields to update' };
297→    }
298→
299→    // Regenerate embedding if title or description changed
300→    if (updateData.title !== undefined || updateData.description !== undefined) {
301→        const resolvedTitle = updateData.title ?? existing.title;
302→        const resolvedDesc = updateData.description ?? (existing.description || '');
303→        const embedding = await GenerateEmbeddings(resolvedTitle, resolvedDesc);
304→        if (embedding && Array.isArray(embedding) && embedding.length > 0) {
305→            updateData.embedding = embedding;
306→        }
307→    }
308→
309→    const { data, error } = await supabase
310→        .from('stories')
311→        .update(updateData)
312→        .eq('id', storyId)
313→        .select(STORY_SELECT_COLUMNS)
314→        .single();
315→
316→    if (error) {
317→        console.error('supabase error updating story:', error.message);
318→        throw { status: 500, error: 'failed to update story' };
319→    }
320→
321→    return stripEmbedding(data);
322→};
