 80→export const getChapterService = async (storyId, chapterId, userId) => {
 81→    if (!storyId || !chapterId) {
 82→        throw { status: 400, error: 'storyId and chapterId are required' };
 83→    }
 84→
 85→    // Fetch story to check privacy
 86→    const { data: story, error: storyError } = await supabase
 87→        .from('stories')
 88→        .select('author_id, privacy')
 89→        .eq('id', storyId)
 90→        .single();
 91→
 92→    if (storyError || !story) {
 93→        throw { status: 404, error: 'story not found' };
 94→    }
 95→
 96→    const isAuthor = story.author_id === userId;
 97→    if (story.privacy === 'private' && !isAuthor) {
 98→        throw { status: 404, error: 'story not found' };
 99→    }
100→
101→    const { data: chapter, error } = await supabase
102→        .from('chapters')
103→        .select('*')
104→        .eq('id', chapterId)
105→        .eq('story_id', storyId)
106→        .single();
107→
108→    if (error || !chapter) {
109→        throw { status: 404, error: 'chapter not found' };
110→    }
111→
112→    // Non-author can't see draft chapters
113→    if (chapter.status === 'draft' && !isAuthor) {
114→        throw { status: 404, error: 'chapter not found' };
115→    }
116→
117→    // Fetch adjacent chapters for navigation
118→    const [prevRes, nextRes] = await Promise.all([
119→        supabase
120→            .from('chapters')
121→            .select('id, chapter_number, title')
122→            .eq('story_id', storyId)
123→            .lt('chapter_number', chapter.chapter_number)
124→            .eq('status', isAuthor ? chapter.status : 'published')
125→            .order('chapter_number', { ascending: false })
126→            .limit(1)
127→            .maybeSingle(),
128→        supabase
129→            .from('chapters')
130→            .select('id, chapter_number, title')
131→            .eq('story_id', storyId)
132→            .gt('chapter_number', chapter.chapter_number)
133→            .eq('status', isAuthor ? chapter.status : 'published')
134→            .order('chapter_number', { ascending: true })
135→            .limit(1)
136→            .maybeSingle(),
137→    ]);
138→
139→    // Increment read count on story (fire and forget)
140→    if (!isAuthor && chapter.status === 'published') {
141→        supabase.rpc('increment_story_reads', { sid: storyId }).then(() => {}).catch(() => {});
142→    }
143→
144→    return {
145→        ...chapter,
146→        prev_chapter: prevRes.data || null,
147→        next_chapter: nextRes.data || null,
148→        is_author: isAuthor,
149→    };
150→};
